    getOptimizationSummary() {
        const summary = {
            totalOptimizations: this.optimizationHistory.length,
            successfulOptimizations: this.optimizationHistory.filter(o => o.result && o.result.success).length,
            totalChanges: this.optimizationHistory.reduce((total, o) => total + (o.result?.changes?.length || 0), 0),
            optimizationsByType: {},
            affectedFiles: new Set()
        };

        // Group optimizations by type
        for (const opt of this.optimizationHistory) {
            if (!summary.optimizationsByType[opt.optimization]) {
                summary.optimizationsByType[opt.optimization] = {
                    attempts: 0,
                    successful: 0,
                    changes: 0
                };
            }
            
            summary.optimizationsByType[opt.optimization].attempts++;
            if (opt.result && opt.result.success) {
                summary.optimizationsByType[opt.optimization].successful++;
            }
            summary.optimizationsByType[opt.optimization].changes += opt.result?.changes?.length || 0;
            
            // Track affected files
            if (opt.result?.changes) {
                for (const change of opt.result.changes) {
                    summary.affectedFiles.add(change.file);
                }
            }
        }

        summary.affectedFiles = Array.from(summary.affectedFiles);

        return summary;
    }

